import test from 'node:test';
import assert from 'node:assert/strict';
import { bundleRecord, calculateBundleAvailability, expandBundleLine, normalizeBundleInput, priceBundle } from '../src/lib/bundles.js';
test('bundle input normalizes components and prices kits', () => { const input = normalizeBundleInput({ title: 'Starter Kit', pricingMode: 'fixed', fixedPriceCents: 4500, items: [{ productId: 'p1', quantity: 2 }, { productId: 'p2', quantity: 1, required: false }] }); assert.equal(input.slug, 'starter-kit'); const bundle = bundleRecord({ id: 'b1', merchant_id: 'm1', title: input.title, slug: input.slug, pricing_mode: 'fixed', fixed_price_cents: 4500, status: 'active' }, [{ id: 'i1', bundle_id: 'b1', product_id: 'p1', quantity: 2, required: 1, unit_price_cents: 3000, inventory_on_hand: 5 }, { id: 'i2', bundle_id: 'b1', product_id: 'p2', quantity: 1, required: 0, unit_price_cents: 1000, inventory_on_hand: 0 }]); assert.equal(bundle.pricing.totalCents, 4500); assert.equal(bundle.pricing.savingsCents, 2500); assert.equal(bundle.availability.maxBundles, 2); });
test('bundle utilities price discounts and expand component demand', () => { assert.equal(priceBundle({ pricingMode: 'percent_discount', discountBps: 1500 }, [{ unitPriceCents: 1000, quantity: 4 }]).totalCents, 3400); assert.equal(calculateBundleAvailability([{ inventoryOnHand: 6, quantity: 2 }, { inventoryOnHand: 3, quantity: 1 }]).maxBundles, 3); assert.equal(expandBundleLine({ id: 'b1', title: 'Kit', items: [{ productId: 'p1', quantity: 2 }] }, 3)[0].quantity, 6); });
